// ---------- Import / Export ----------

export const importExportApi = {
  importMspdi: async (projectId: string, file: File) => {
    const form = new FormData();
    form.append('file', file);
    const res = await fetch(
      `${BASE}/projects/${projectId}/import/mspdi`,
      { method: 'POST', body: form },
    );
    if (!res.ok) throw new Error('Import failed');
    return res.json();
  },

  exportMspdi: async (projectId: string) => {
    const res = await fetch(
      `${BASE}/projects/${projectId}/export/mspdi`,
    );
    if (!res.ok) throw new Error('Export failed');
    return res.blob();
  },

  previewUpdates: async (projectId: string, file: File) => {
    const form = new FormData();
    form.append('file', file);
    const res = await fetch(
      `${BASE}/projects/${projectId}/import/preview`,
      { method: 'POST', body: form },
    );
    if (!res.ok) throw new Error('Preview failed');
    return res.json();
  },

  applyUpdates: async (
    projectId: string,
    file: File,
    options?: Record<string, unknown>,
  ) => {
    const form = new FormData();
    form.append('file', file);
    if (options) form.append('options', JSON.stringify(options));
    const res = await fetch(
      `${BASE}/projects/${projectId}/import/apply`,
      { method: 'POST', body: form },
    );
    if (!res.ok) throw new Error('Apply failed');
    return res.json();
  },

  undo: (projectId: string) =>
    request<{ success: boolean }>(`/projects/${projectId}/undo`, {
      method: 'POST',
    }),
  redo: (projectId: string) =>
    request<{ success: boolean }>(`/projects/${projectId}/redo`, {
      method: 'POST',
    }),
};

// ---------- AI ----------

export interface AiChatResponse {
  conversationId: string;
  response: string;
}

export interface AiSuggestionResponse {
  suggestion: string;
}

export interface AiHealthResponse {
  ollamaAvailable: boolean;
  models: string[];
}

export interface AiConversationSummary {
  id: string;
  createdAt: string;
  updatedAt: string;
}

export interface AiPatternEntry {
  id: string;
  patternType: string;
  pattern: string;
  confidence: number;
  occurrenceCount: number;
}

export const aiApi = {
  health: () => request<AiHealthResponse>('/ai/health'),

  chat: (projectId: string, message: string, conversationId?: string) =>
    request<AiChatResponse>('/ai/chat', {
      method: 'POST',
      body: JSON.stringify({ projectId, message, conversationId }),
    }),

  suggest: (
    projectId: string,
    type: 'duration' | 'dependency' | 'name' | 'resource' | 'general',
    context: Record<string, unknown>,
  ) =>
    request<AiSuggestionResponse>('/ai/suggest', {
      method: 'POST',
      body: JSON.stringify({ projectId, type, context }),
    }),

  feedback: (
    projectId: string,
    suggestionType: string,
    suggestion: Record<string, unknown>,
    accepted: boolean,
    correctedValue?: string,
  ) =>
    request<void>('/ai/feedback', {
      method: 'POST',
      body: JSON.stringify({
        projectId,
        suggestionType,
        suggestion,
        accepted,
        correctedValue,
      }),
    }),

  listConversations: (projectId: string) =>
    request<AiConversationSummary[]>(
      `/ai/conversations?projectId=${encodeURIComponent(projectId)}`,
    ),

  getConversation: (id: string) =>
    request<{
      id: string;
      projectId: string;
      messages: { role: string; content: string }[];
    }>(`/ai/conversations/${id}`),

  deleteConversation: (id: string) =>
    request<void>(`/ai/conversations/${id}`, { method: 'DELETE' }),

  getPatterns: () => request<AiPatternEntry[]>('/ai/patterns'),

  getFeedbackStats: () =>
    request<{ total: number; accepted: number; acceptanceRate: number }>(
      '/ai/feedback/stats',
    ),
};

